const CONFIG = {
  // Ten sekret musi być taki sam jak N8N_SHARED_SECRET w /opt/baza_mennica/app.env
  mennicaSharedSecret: '5d187b65dc00f999d276899dcf9418651fd289363f06d4d6ee2f8f974a9080c7',

  // Uzupełnij przed aktywacją workflow
  openaiApiKey: 'PASTE_OPENAI_API_KEY',
  airtableApiKey: 'PASTE_AIRTABLE_API_KEY',
  airtableBaseId: 'PASTE_AIRTABLE_BASE_ID',
  airtableTableName: 'Mennica QA',

  openaiModel: 'gpt-4o-mini-transcribe'
};

function assertConfigured(name, value) {
  if (!value || String(value).startsWith('PASTE_')) {
    throw new Error(`Uzupełnij CONFIG.${name} w node Code przed aktywacją workflow.`);
  }
}

function readSecret(headers = {}) {
  return headers['x-n8n-secret'] || headers['X-N8N-Secret'] || headers['X-N8n-Secret'] || '';
}

async function fetchJson(url, options) {
  const response = await fetch(url, options);
  const text = await response.text();
  let json = null;
  try {
    json = text ? JSON.parse(text) : null;
  } catch (err) {
    json = { raw: text };
  }
  if (!response.ok) {
    throw new Error(`${options?.method || 'GET'} ${url} failed ${response.status}: ${text.slice(0, 500)}`);
  }
  return json;
}

const webhook = $input.first().json;
const payload = webhook.body || webhook;
const headers = webhook.headers || {};

if (readSecret(headers) !== CONFIG.mennicaSharedSecret) {
  throw new Error('Unauthorized: invalid X-N8N-Secret.');
}

assertConfigured('openaiApiKey', CONFIG.openaiApiKey);
assertConfigured('airtableApiKey', CONFIG.airtableApiKey);
assertConfigured('airtableBaseId', CONFIG.airtableBaseId);

const requiredFields = ['answer_id', 'question_id', 'question', 'category', 'audio_download_url', 'callback_url'];
for (const field of requiredFields) {
  if (!payload[field]) throw new Error(`Missing payload field: ${field}`);
}

const audioResponse = await fetch(payload.audio_download_url, {
  headers: { 'X-N8N-Secret': CONFIG.mennicaSharedSecret }
});
if (!audioResponse.ok) {
  throw new Error(`Audio download failed ${audioResponse.status}: ${await audioResponse.text()}`);
}

const audioBuffer = await audioResponse.arrayBuffer();
const form = new FormData();
form.append('model', CONFIG.openaiModel);
form.append('file', new Blob([audioBuffer], { type: 'audio/mpeg' }), `answer-${payload.answer_id}.mp3`);

const transcriptionResponse = await fetch('https://api.openai.com/v1/audio/transcriptions', {
  method: 'POST',
  headers: { Authorization: `Bearer ${CONFIG.openaiApiKey}` },
  body: form
});
const transcriptionText = await transcriptionResponse.text();
let transcription = null;
try {
  transcription = JSON.parse(transcriptionText);
} catch (err) {
  transcription = { raw: transcriptionText };
}
if (!transcriptionResponse.ok) {
  throw new Error(`OpenAI transcription failed ${transcriptionResponse.status}: ${transcriptionText.slice(0, 500)}`);
}
const transcript = transcription.text || '';
if (!transcript.trim()) {
  throw new Error('OpenAI returned empty transcript.');
}

const airtableUrl = `https://api.airtable.com/v0/${CONFIG.airtableBaseId}/${encodeURIComponent(CONFIG.airtableTableName)}`;
const airtablePayload = {
  performUpsert: {
    fieldsToMergeOn: ['Answer ID']
  },
  records: [
    {
      fields: {
        'Question ID': String(payload.question_id),
        'Answer ID': String(payload.answer_id),
        'Category': payload.category || '',
        'Question': payload.question || '',
        'Transcript': transcript,
        'Audio URL': payload.audio_download_url || '',
        'Recorded At': payload.recorded_at || new Date().toISOString(),
        'Status': 'transcribed'
      }
    }
  ]
};

const airtableResult = await fetchJson(airtableUrl, {
  method: 'PATCH',
  headers: {
    Authorization: `Bearer ${CONFIG.airtableApiKey}`,
    'Content-Type': 'application/json'
  },
  body: JSON.stringify(airtablePayload)
});

const callbackResult = await fetchJson(payload.callback_url, {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'X-N8N-Secret': CONFIG.mennicaSharedSecret
  },
  body: JSON.stringify({
    answer_id: payload.answer_id,
    transcript,
    transcript_status: 'done'
  })
});

return [
  {
    json: {
      ok: true,
      answer_id: payload.answer_id,
      question_id: payload.question_id,
      transcript_chars: transcript.length,
      airtable_record_id: airtableResult.records?.[0]?.id || null,
      callback: callbackResult
    }
  }
];
